const body = ($('Webhook').first().json.body) || {};
if (!body.token) return [{ json: { valid:false, error:'token obligatorio' } }];
if (!body.question || body.question.toString().length < 3) return [{ json: { valid:false, error:'question >= 3 chars obligatorio' } }];
return [{ json: { valid:true, token: body.token, question: body.question.toString().slice(0,2000) } }];

const promptRow = $input.first().json;
const ctx = $('Load Project Context').first().json.context;
const question = $('Validate Input').first().json.question;
const tokenInfo = $('Validate Token').first().json;
const prompt_user = `CONTEXTO DEL PROYECTO DEL CLIENTE:
Nombre proyecto: ${ctx.project_name}
Cliente: ${ctx.client_name}
Tipo: ${ctx.project_type} (${ctx.property_type}, ${ctx.property_area_m2} m2)
Ubicacion: ${ctx.location_city}
Fase actual: ${ctx.current_phase}
Budget objetivo: ${ctx.budget_target || '(no definido)'} EUR
Presupuesto estimado: ${ctx.cost_estimate_total || '(pendiente)'} EUR
Fecha inicio: ${ctx.started_at || '(no definida)'}
Fecha objetivo entrega: ${ctx.target_completion || '(no definida)'}
Fecha entrega real (handover): ${ctx.handover_date || '(no entregado)'}

Resumen briefing aprobado: ${ctx.briefing_summary || '(no disponible)'}
Diseno seleccionado: ${ctx.design_option ? ctx.design_option.title + ' — ' + (ctx.design_option.description || '').substring(0,200) : '(no seleccionado)'}
Incidencias post-entrega activas: ${ctx.has_active_aftercare ? 'SI' : 'NO'}

---

PREGUNTA DEL CLIENTE:
${question}

---

Responde en JSON segun schema. Recuerda escalar al arquitecto Damian si la pregunta requiere decision profesional o si te falta info.`;
return [{ json: { agent_name: 'agent_client_concierge', prompt_system: promptRow.content, prompt_user: prompt_user, model: promptRow.model_recommended || 'gpt-4o-mini', temperature: promptRow.temperature !== null ? Number(promptRow.temperature) : 0.4, project_id: ctx.project_id, question: question, token_id: tokenInfo.token_id } }];

const llm = $input.first().json;
let text = llm.text || llm.content || '';
text = text.replace(/^```(?:json)?\s*/i,'').replace(/```\s*$/i,'').trim();
let parsed;
try { parsed = JSON.parse(text); } catch(e) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch(_) {} }
}
if (!parsed) {
  parsed = { answer: 'Disculpa, no he podido procesar tu pregunta correctamente. Te he derivado al arquitecto y se pondra en contacto contigo en breve.', escalate: true, escalation_reason: 'parse_failure', data_used: [] };
}
return [{ json: { answer: parsed.answer || '', escalate: !!parsed.escalate, escalation_reason: parsed.escalation_reason || null, data_used: Array.isArray(parsed.data_used) ? parsed.data_used : [], llm_model: llm.model || 'gpt-4o-mini', llm_tokens_in: llm.tokens_in || null, llm_tokens_out: llm.tokens_out || null, llm_cost_usd: llm.cost_estimated || null } }];

parameters.query:
INSERT INTO client_conversations (project_id, token_id, question, answer, escalated, escalation_reason, llm_model, llm_tokens_in, llm_tokens_out, llm_cost_usd, client_ip, answered_at)
VALUES ($1::uuid, $2::uuid, $3, $4, $5::boolean, $6, $7, $8::int, $9::int, $10::numeric, $11, now())
RETURNING id, escalated;
